import io.gatling.javaapi.core.*;
import io.gatling.javaapi.http.*;
import static io.gatling.javaapi.core.CoreDsl.*;
import static io.gatling.javaapi.http.HttpDsl.*;
import java.util.*;

public class PaymentWithFeederSimulation extends Simulation {

    // merchants.csv (src/test/resources/merchants.csv):
    // merchantId,apiKey,amount
    // MRC-001,key_rzp_live_001,999.00
    // MRC-002,key_rzp_live_002,1499.00
    // ... 1000 rows for realistic load

    FeederBuilder.Batchable<String> merchantFeeder = csv("merchants.csv").random();
    // .random(): random selection per user (default: csv().circular() = round-robin)
    // .circular(): cycle through rows sequentially (predictable, less realistic)
    // .random() preferred: simulates real traffic distribution (some merchants more active)

    HttpProtocolBuilder httpProtocol = http.baseUrl("http://staging.razorpay.internal");

    ScenarioBuilder paymentScenario = scenario("Payment with Feeder")
        .feed(merchantFeeder)  // inject feeder values into session
        .exec(
            http("POST /api/payments")
                .post("/api/payments")
                .header("X-API-Key", "#{apiKey}")     // from feeder
                .header("Content-Type", "application/json")
                .body(StringBody("""
                    {
                      \"merchant_id\": \"#{merchantId}\",
                      \"amount\": #{amount},
                      \"gateway\": \"visa\"
                    }
                """))
                .check(status().is(200))
        );
    // RANDOM vs CIRCULAR:
    // Random: each user picks a random row → realistic cache miss distribution
    // Circular: user 1 → row 1, user 2 → row 2, ... wraps around
    // Problem with circular under 10 users: same 10 merchants in rotation
    //   → DB caches those 10 merchants specifically → unrealistically fast!
    // Random with 1000 rows: cold cache for most requests → realistic DB load
    { setUp(paymentScenario.injectOpen(rampUsers(50).during(30))).protocols(httpProtocol); }
}

