public class PaymentFlowSimulation extends Simulation {
    HttpProtocolBuilder httpProtocol = http.baseUrl("http://staging.razorpay.internal");

    ScenarioBuilder paymentFlow = scenario("Payment Flow")
        .exec(
            http("1. Create Payment")
                .post("/api/payments")
                .header("Content-Type", "application/json")
                .body(StringBody("""
                    {\"merchant_id\": \"MRC-001\", \"amount\": 999.00, \"gateway\": \"visa\"}
                """))
                .check(
                    status().is(200),
                    jsonPath("$.id").saveAs("paymentId"),     // extract and save response field
                    jsonPath("$.status").is("PENDING")
                )
        )
        .pause(1)  // 1 second think time (user reads confirmation)
        .exec(
            http("2. Check Payment Status")
                .get("/api/payments/#{paymentId}")   // use captured ID from step 1
                .check(
                    status().is(200),
                    jsonPath("$.status").in("PENDING", "COMPLETED")  // valid statuses
                )
        );

    {
        setUp(
            paymentFlow.injectOpen(
                atOnceUsers(5),
                rampUsers(50).during(30),
                constantUsersPerSec(25).during(120)
            )
        ).protocols(httpProtocol)
         .assertions(
             global().responseTime().percentile(99).lt(300),
             global().successfulRequests().percent().gt(99.9)
         );
    }
}

import io.gatling.javaapi.core.*;
import static io.gatling.javaapi.core.CoreDsl.*;

// SPIKE TEST: tests resilience to sudden traffic bursts
// (Diwali sale, market open at 9:15am, viral social media moment)
class SpikeTestProfile {
    static OpenInjectionStep[] profile() {
        return new OpenInjectionStep[]{
            constantUsersPerSec(50).during(60),   // normal: 50 req/s for 1 min
            rampUsersPerSec(50).to(500).during(10), // SPIKE: 50→500 req/s in 10s
            constantUsersPerSec(500).during(60),  // at spike: 500 req/s for 1 min
            rampUsersPerSec(500).to(50).during(30),// recovery: back to normal
            constantUsersPerSec(50).during(60)    // normal: verify recovery
        };
    }
    // REVEALS:
    // Does circuit breaker fire appropriately during spike?
    // Does autoscaler respond in time?
    // Does error rate spike then recover or stay elevated?
    // Are queues/pools exhausted? (connectionTimeout, HikariCP pending)
}

// SOAK TEST: sustained moderate load for extended duration
// (detects memory leaks, connection leaks, thread pool degradation over time)
class SoakTestProfile {
    static OpenInjectionStep[] profile() {
        return new OpenInjectionStep[]{
            rampUsers(100).during(120),              // ramp to working load
            constantUsersPerSec(50).during(1800)     // sustain 30 minutes
        };
    }
    // REVEALS:
    // Memory leaks: heap grows over 30 min → GC pressure → OOM
    // Connection leaks: HikariCP pool exhausted after thousands of requests
    // Thread leaks: Tomcat thread pool degrading
    // Log file: disk fills up (common in staging!)
    // Metric: jvm.memory.used rising over 30 min → heap leak
}

public class SpikeAndSoakGuide { public static void main(String[] a) {
    System.out.println("Spike: tests resilience. Soak: detects leaks over time."); } }

