import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

// METRICS TO WATCH DURING LOAD TEST:
// 1. JVM:
//    jvm_gc_pause_seconds_max: should stay < 0.1 (100ms)
//    jvm_memory_used_bytes{area='heap'}: should stay stable (no leak)
//    jvm_threads_live: should not grow indefinitely
//
// 2. HikariCP:
//    hikaricp_connections_pending: should stay 0 (pool not exhausted)
//    hikaricp_connections_active: should be < maximumPoolSize
//    hikaricp_connections_acquire_seconds_max: should stay < 0.01s
//
// 3. HTTP:
//    http_server_requests_seconds{percentile='0.99'}: main SLO metric
//    http_server_requests_active: concurrent requests (should be bounded)
//
// 4. Cache (Caffeine):
//    cache_hits_total{level='l1'}: should be > 40% of all cache accesses
//    cache_hits_total{level='db'}: should stay < 5%
//
// 5. DB:
//    db_query_duration_seconds{percentile='0.99'}: should stay < 0.05s

@SpringBootTest
class LoadTestMetricsTest {
    @Autowired MeterRegistry reg;

    @Test void jvmMetrics_present() {
        assertNotNull(reg.find("jvm.gc.pause").timers().stream().findAny().orElse(null)
            == null ? reg.find("jvm.memory.used").gauge() : reg.find("jvm.gc.pause").timers().iterator().next());
    }

    @Test void hikariMetrics_registered() {
        Gauge maxPool = reg.find("hikaricp.connections.max").gauge();
        assertNotNull(maxPool, "HikariCP connection max should be registered");
        assertTrue(maxPool.value() > 0, "Pool should have > 0 max connections");
    }

    @Test void allRequiredMetrics_available() {
        // Verify the metrics landscape is populated:
        assertTrue(reg.getMeters().size() > 20,
            "Should have many JVM + app metrics registered");
        System.out.println("Total metrics registered: " + reg.getMeters().size());
    }
}

