public class AuthenticatedPaymentSimulation extends Simulation {
    HttpProtocolBuilder httpProtocol = http.baseUrl("http://staging.razorpay.internal");

    ChainBuilder authenticate = exec(
        http("POST /auth/token")
            .post("/auth/token")
            .header("Content-Type", "application/json")
            .body(StringBody("""
                {\"clientId\":\"rzp_test_client\",\"clientSecret\":\"#{clientSecret}\"}
            """))
            .check(
                status().is(200),
                jsonPath("$.access_token").saveAs("jwtToken"),
                jsonPath("$.expires_in").saveAs("expiresIn")
            )
    );

    ChainBuilder processPayment = exec(
        http("POST /api/payments")
            .post("/api/payments")
            .header("Authorization", "Bearer #{jwtToken}")
            .header("Content-Type", "application/json")
            .body(StringBody("{\"amount\":999.00,\"gateway\":\"visa\"}"))
            .check(status().is(200))
    );

    ScenarioBuilder authFlow = scenario("Authenticated Payment")
        .feed(csv("credentials.csv").circular())
        .exec(authenticate)                        // get initial token
        .repeat(50).on(
            exec(processPayment).pause(100)
        )
        .exec(authenticate);                        // refresh token after 50 requests

    {
        setUp(authFlow.injectOpen(
            atOnceUsers(5), rampUsers(50).during(30)
        )).protocols(httpProtocol)
         .assertions(
             details("POST /auth/token").responseTime().percentile(99).lt(50),
             details("POST /api/payments").responseTime().percentile(99).lt(200),
             global().successfulRequests().percent().gt(99.9)
         );
    }
}

