import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

class CapacityPlanner {
    // CURRENT MEASUREMENTS:
    // 200 req/s → p99=150ms, CPU=50%
    // At 100% CPU (2× load): p99 likely exceeds 200ms
    // Safe capacity: 80% of max = 80% × 400 = 320 req/s per pod (with headroom)

    static double safeCapacityPerPod(double observedReqPerSec, double observedCpuPercent) {
        // Linear extrapolation: find 80% CPU level
        double maxReqPerSec = observedReqPerSec * (100.0 / observedCpuPercent);
        // 80% capacity rule: leave 20% headroom for spikes
        return maxReqPerSec * 0.80;
    }

    static int podsRequired(double targetThroughput, double safeCapacityPerPod) {
        return (int) Math.ceil(targetThroughput / safeCapacityPerPod);
    }

    static int podsWithBuffer(int requiredPods, double bufferFactor) {
        // Add buffer for rolling updates, pod failures, autoscaler lag:
        return (int) Math.ceil(requiredPods * bufferFactor);
    }
}

class CapacityCalculationTest {
    @Test void diwaliCapacityCalculation() {
        // Observed: 200 req/s at 50% CPU
        double safeCapacity = CapacityPlanner.safeCapacityPerPod(200, 50);
        // (200 / 0.50) × 0.80 = 400 × 0.80 = 320 req/s per pod
        assertEquals(320.0, safeCapacity, 1.0, "Safe capacity per pod should be 320 req/s");

        // Diwali: 1500 req/s target
        int basePodsNeeded = CapacityPlanner.podsRequired(1500, safeCapacity);
        // ceil(1500/320) = ceil(4.69) = 5 pods
        assertEquals(5, basePodsNeeded, "Need 5 pods for 1500 req/s");

        // Add 40% buffer (rolling updates consume 1 pod, pod failure, autoscaler lag):
        int totalPods = CapacityPlanner.podsWithBuffer(basePodsNeeded, 1.4);
        // ceil(5 × 1.4) = ceil(7) = 7 pods
        assertEquals(7, totalPods, "With 40% buffer: deploy 7 pods for Diwali");

        System.out.printf("Diwali capacity plan: %d pods (5 needed + 2 buffer)%n", totalPods);
    }
}

