// Capacity planning math:
class M22CapacityMath {
    static double safeCapacity(double reqPerSec, double cpuPct){
        return (reqPerSec/cpuPct)*100*0.80;
    }
    static int podsNeeded(double target, double safe, double buffer){
        return (int)Math.ceil((target/safe)*buffer);
    }
}

@SpringBootTest
class M22SynthesisTest {
    @Autowired MeterRegistry reg;

    @Test void allM22Metrics_present(){
        assertNotNull(reg.find("jvm.memory.used").gauge(),     "T22.1: JVM metrics");
        assertNotNull(reg.find("hikaricp.connections.max").gauge(), "T22.3: HikariCP metrics");
        assertTrue(reg.getMeters().size()>15, "Should have many auto-registered meters");
    }

    @Test void capacityMath_correct(){
        double safe=M22CapacityMath.safeCapacity(200,50);
        assertEquals(320.0,safe,1.0);
        int pods=M22CapacityMath.podsNeeded(1500,safe,1.4);
        assertEquals(7,pods);
    }

    @Test void simulationClass_compiles(){
        // Verify simulation can be instantiated (Gatling class loading):
        assertDoesNotThrow(()->new M22SynthesisSimulation(),
            "Gatling simulation should compile and instantiate");
    }
}
